"use client";

import { useMemo, useState } from "react";
import type {
  KnowledgeGraphEdge,
  KnowledgeGraphNode,
  KnowledgeGraphPayload
} from "@/lib/github-knowledge-graph";

interface PositionedNode extends KnowledgeGraphNode {
  x: number;
  y: number;
}

export function KnowledgeGraphViewer({ graph }: { graph: KnowledgeGraphPayload }) {
  const [query, setQuery] = useState("");
  const [selectedId, setSelectedId] = useState(graph.nodes[0]?.id ?? "");

  const selectedNode = graph.nodes.find((node) => node.id === selectedId) ?? graph.nodes[0];
  const connectedEdgeIds = useMemo(
    () =>
      new Set(
        graph.edges
          .filter((edge) => edge.source === selectedNode?.id || edge.target === selectedNode?.id)
          .map((edge) => edge.id)
      ),
    [graph.edges, selectedNode?.id]
  );
  const connectedNodeIds = useMemo(() => {
    const ids = new Set<string>(selectedNode ? [selectedNode.id] : []);
    for (const edge of graph.edges) {
      if (edge.source === selectedNode?.id) {
        ids.add(edge.target);
      }
      if (edge.target === selectedNode?.id) {
        ids.add(edge.source);
      }
    }
    return ids;
  }, [graph.edges, selectedNode?.id]);

  const positionedNodes = useMemo(() => layoutNodes(graph.nodes), [graph.nodes]);
  const nodesById = useMemo(
    () => new Map(positionedNodes.map((node) => [node.id, node])),
    [positionedNodes]
  );
  const normalizedQuery = query.trim().toLowerCase();
  const matchingIds = useMemo(() => {
    if (!normalizedQuery) {
      return new Set(graph.nodes.map((node) => node.id));
    }

    return new Set(
      graph.nodes
        .filter((node) =>
          [node.label, node.path, node.summary, ...(node.tags ?? [])]
            .filter(Boolean)
            .join(" ")
            .toLowerCase()
            .includes(normalizedQuery)
        )
        .map((node) => node.id)
    );
  }, [graph.nodes, normalizedQuery]);
  const visibleEdges = graph.edges.filter((edge) => {
    if (!normalizedQuery) {
      return true;
    }

    return matchingIds.has(edge.source) || matchingIds.has(edge.target);
  });

  return (
    <div className="graph-viewer">
      <section className="graph-toolbar" aria-label="Controlli grafo">
        <div>
          <span className="eyebrow">Repository GitHub</span>
          <h1>Grafo knowledge</h1>
          <p>
            Vista navigabile del branch <strong>{graph.branch}</strong>, cartella{" "}
            <strong>{graph.root}</strong>.
          </p>
        </div>
        <div className="graph-actions">
          <label className="graph-search">
            <span className="visually-hidden">Cerca nel grafo</span>
            <input
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Cerca concetto, file o tag"
            />
          </label>
          <a className="graph-source-link" href={graph.sourceUrl} target="_blank" rel="noreferrer">
            Apri repository
          </a>
        </div>
      </section>

      {graph.error ? <p className="graph-error">GitHub non ha risposto: {graph.error}</p> : null}

      <section className="graph-stats" aria-label="Statistiche grafo">
        <Metric label="Documenti" value={graph.stats.documents} />
        <Metric label="Cartelle" value={graph.stats.folders} />
        <Metric label="Tag" value={graph.stats.tags} />
        <Metric label="Rimandi" value={graph.stats.references} />
      </section>

      <section className="graph-workbench">
        <div className="graph-canvas-panel">
          <svg className="knowledge-svg" viewBox="0 0 920 640" role="img" aria-label="Grafo della knowledge base">
            <defs>
              <marker
                id="graph-arrow"
                viewBox="0 0 10 10"
                refX="8"
                refY="5"
                markerWidth="5"
                markerHeight="5"
                orient="auto-start-reverse"
              >
                <path d="M 0 0 L 10 5 L 0 10 z" />
              </marker>
            </defs>

            {visibleEdges.map((edge) => {
              const source = nodesById.get(edge.source);
              const target = nodesById.get(edge.target);
              if (!source || !target) {
                return null;
              }

              const active = connectedEdgeIds.has(edge.id);
              const muted =
                normalizedQuery &&
                !matchingIds.has(edge.source) &&
                !matchingIds.has(edge.target);

              return (
                <line
                  key={edge.id}
                  className={`graph-edge graph-edge-${edge.type}${active ? " active" : ""}${
                    muted ? " muted" : ""
                  }`}
                  x1={source.x}
                  y1={source.y}
                  x2={target.x}
                  y2={target.y}
                  markerEnd={edge.type === "contains" ? undefined : "url(#graph-arrow)"}
                />
              );
            })}

            {positionedNodes.map((node) => {
              const selected = node.id === selectedNode?.id;
              const related = connectedNodeIds.has(node.id);
              const muted = normalizedQuery && !matchingIds.has(node.id) && !related;

              return (
                <g
                  key={node.id}
                  className={`graph-node graph-node-${node.type}${selected ? " selected" : ""}${
                    related ? " related" : ""
                  }${muted ? " muted" : ""}`}
                  transform={`translate(${node.x} ${node.y})`}
                  role="button"
                  tabIndex={0}
                  aria-label={`Seleziona ${node.label}`}
                  onClick={() => setSelectedId(node.id)}
                  onKeyDown={(event) => {
                    if (event.key === "Enter" || event.key === " ") {
                      event.preventDefault();
                      setSelectedId(node.id);
                    }
                  }}
                >
                  <circle r={nodeRadius(node.type)} />
                  <text y={node.type === "document" ? 28 : 24}>{node.label}</text>
                </g>
              );
            })}
          </svg>
        </div>

        <aside className="graph-detail" aria-label="Dettaglio nodo selezionato">
          {selectedNode ? (
            <>
              <span className={`graph-type graph-type-${selectedNode.type}`}>
                {nodeTypeLabel(selectedNode.type)}
              </span>
              <h2>{selectedNode.label}</h2>
              {selectedNode.path ? <p className="graph-path">{selectedNode.path}</p> : null}
              {selectedNode.summary ? <p>{selectedNode.summary}</p> : null}
              {selectedNode.tags?.length ? (
                <div className="graph-tags">
                  {selectedNode.tags.map((tag) => (
                    <button key={tag} type="button" onClick={() => setQuery(tag)}>
                      {tag}
                    </button>
                  ))}
                </div>
              ) : null}
              {selectedNode.url ? (
                <a className="graph-detail-link" href={selectedNode.url} target="_blank" rel="noreferrer">
                  Apri su GitHub
                </a>
              ) : null}
              <RelatedList
                edges={graph.edges}
                nodes={graph.nodes}
                selectedId={selectedNode.id}
                onSelect={setSelectedId}
              />
            </>
          ) : (
            <p>Nessun nodo selezionato.</p>
          )}
        </aside>
      </section>

      <p className="graph-footnote">
        Aggiornato: {new Intl.DateTimeFormat("it-IT", { dateStyle: "medium", timeStyle: "short" }).format(new Date(graph.generatedAt))}
      </p>
    </div>
  );
}

function Metric({ label, value }: { label: string; value: number }) {
  return (
    <div className="graph-metric">
      <span>{label}</span>
      <strong>{value}</strong>
    </div>
  );
}

function RelatedList({
  edges,
  nodes,
  selectedId,
  onSelect
}: {
  edges: KnowledgeGraphEdge[];
  nodes: KnowledgeGraphNode[];
  selectedId: string;
  onSelect: (id: string) => void;
}) {
  const nodesById = new Map(nodes.map((node) => [node.id, node]));
  const related = edges
    .filter((edge) => edge.source === selectedId || edge.target === selectedId)
    .map((edge) => {
      const node = nodesById.get(edge.source === selectedId ? edge.target : edge.source);
      return node ? { edge, node } : null;
    })
    .filter((item): item is { edge: KnowledgeGraphEdge; node: KnowledgeGraphNode } => Boolean(item))
    .slice(0, 12);

  return (
    <div className="graph-related">
      <h3>Collegamenti</h3>
      {related.length ? (
        <ul>
          {related.map(({ edge, node }) => (
            <li key={`${edge.id}-${node.id}`}>
              <button type="button" onClick={() => onSelect(node.id)}>
                <span>{edge.label}</span>
                {node.label}
              </button>
            </li>
          ))}
        </ul>
      ) : (
        <p>Nessun collegamento diretto.</p>
      )}
    </div>
  );
}

function layoutNodes(nodes: KnowledgeGraphNode[]): PositionedNode[] {
  const center = { x: 460, y: 320 };
  const groups = {
    root: nodes.filter((node) => node.type === "root"),
    folder: nodes.filter((node) => node.type === "folder"),
    document: nodes.filter((node) => node.type === "document"),
    tag: nodes.filter((node) => node.type === "tag")
  };

  return [
    ...groups.root.map((node) => ({ ...node, ...center })),
    ...placeOnRing(groups.folder, center, 125, -Math.PI / 2),
    ...placeOnRing(groups.document, center, 230, -Math.PI / 2),
    ...placeOnRing(groups.tag, center, 300, -Math.PI / 2)
  ];
}

function placeOnRing(
  nodes: KnowledgeGraphNode[],
  center: { x: number; y: number },
  radius: number,
  startAngle: number
): PositionedNode[] {
  if (!nodes.length) {
    return [];
  }

  return nodes.map((node, index) => {
    const angle = startAngle + (Math.PI * 2 * index) / nodes.length;
    return {
      ...node,
      x: Math.round(center.x + Math.cos(angle) * radius),
      y: Math.round(center.y + Math.sin(angle) * radius)
    };
  });
}

function nodeRadius(type: KnowledgeGraphNode["type"]): number {
  switch (type) {
    case "root":
      return 26;
    case "folder":
      return 18;
    case "tag":
      return 13;
    default:
      return 15;
  }
}

function nodeTypeLabel(type: KnowledgeGraphNode["type"]): string {
  switch (type) {
    case "root":
      return "radice";
    case "folder":
      return "sezione";
    case "tag":
      return "tema";
    default:
      return "documento";
  }
}
